bad_examples:
// ❌ unsafe
const fn = new URLSearchParams(window.location.search).get('action');
window[fn](); // ?action=eval → window.eval()

good_examples:
// ✅ safe - explicit allowlist
const ALLOWED = ['openMenu', 'closeModal', 'refreshData'];
const fn = new URLSearchParams(window.location.search).get('action');
if (ALLOWED.includes(fn)) (window as any)[fn]();

bad_examples:
// ❌ unsafe
const config = JSON.parse(window.name);
document.getElementById('output').innerHTML = config.html;

good_examples:
// ✅ safe - use postMessage with origin check instead
window.addEventListener('message', (e) => {
  if (e.origin !== 'https://trusted.example.com') return;
  document.getElementById('output').textContent = JSON.parse(e.data).text;
});

bad_examples:
// ❌ unsafe - readable by any script
window.authToken = getAuthToken();
window.apiKey = 'sk-live-abc123';

good_examples:
// ✅ safe - module-scoped closure
const tokenStore = (() => {
  let token: string | null = null;
  return { set: (t: string) => { token = t; }, get: () => token };
})();

bad_examples:
// ❌ unsafe
const tmpl = req.body.template;
const compiled = _.template(tmpl, { variable: 'data' });
const output = compiled({ user }); // RCE

good_examples:
// ✅ safe - compile only static literal templates
const compiled = _.template('Hello <%= data.name %>!', { variable: 'data' });
const output = compiled({ name: _.escape(userInput) });

bad_examples:
// ❌ unsafe
import { marked } from 'marked';
const html = marked.parse(userMarkdown);
document.getElementById('output').innerHTML = html;
// [click me](javascript:alert(1)) executes

good_examples:
// ✅ safe
import { marked } from 'marked';
import DOMPurify from 'dompurify';
const html = DOMPurify.sanitize(marked.parse(userMarkdown));
document.getElementById('output').innerHTML = html;

bad_examples:
// ❌ unsafe
const clean = DOMPurify.sanitize(input, {
  ALLOWED_TAGS: ['p', 'b', 'script'],
  ADD_ATTR: ['onclick', 'onerror'],
  ALLOW_UNKNOWN_PROTOCOLS: true
});

good_examples:
// ✅ safe - minimal safe subset
const clean = DOMPurify.sanitize(input, {
  ALLOWED_TAGS: ['p', 'b', 'i', 'em', 'strong', 'a'],
  ALLOWED_ATTR: ['href', 'title'],
  FORCE_BODY: true
});

bad_examples:
// ❌ unsafe
const clean = sanitizeHtml(input, {
  allowedTags: ['p', 'b', 'script', 'iframe'],
  allowedAttributes: { '*': ['onerror', 'onload'] }
});

good_examples:
// ✅ safe
const clean = sanitizeHtml(input, {
  allowedTags: ['p', 'b', 'i', 'em', 'strong'],
  allowedAttributes: { 'a': ['href'] }
});

bad_examples:
// ❌ unsafe
import Handlebars from 'handlebars';
const tmpl = req.body.template;
const html = Handlebars.compile(tmpl)({ user }); // RCE

good_examples:
// ✅ safe - static developer-defined template only
import Handlebars from 'handlebars';
const compiled = Handlebars.compile('<p>Hello {{name}}</p>');
const html = compiled({ name: Handlebars.escapeExpression(userInput) });

bad_examples:
// ❌ unsafe
import nunjucks from 'nunjucks';
const output = nunjucks.renderString(req.body.template, { user });
// {{ range.constructor("return global.process.env")() }}

good_examples:
// ✅ safe - user data as context, static template file
import nunjucks from 'nunjucks';
const output = nunjucks.render('email.html', {
  name: req.body.name,
  message: req.body.message
});

bad_examples:
// ❌ unsafe
import { Eta } from 'eta';
const eta = new Eta();
const output = eta.renderString(req.body.template, { user });
// <%~ process.mainModule.require('child_process').execSync('id') %>

good_examples:
// ✅ safe - render static template files
import { Eta } from 'eta';
const eta = new Eta({ views: path.join(__dirname, 'templates') });
const output = eta.render('welcome.eta', { name: sanitize(req.body.name) });

bad_examples:
// ❌ unsafe
import superjson from 'superjson';
const data = superjson.parse(req.body.data);
// { "json": { "__proto__": { "isAdmin": true } } }

good_examples:
// ✅ safe - schema validation before deserializing
import superjson from 'superjson';
import { z } from 'zod';
const schema = z.object({ name: z.string(), age: z.number() });
const data = schema.parse(superjson.parse(req.body.data));

bad_examples:
// ❌ unsafe
import * as devalue from 'devalue';
const data = devalue.parse(req.body.serialized);

good_examples:
// ✅ safe - validate after parsing
import * as devalue from 'devalue';
import { z } from 'zod';
const schema = z.object({ id: z.string(), value: z.number() });
const data = schema.parse(devalue.parse(req.body.serialized));

bad_examples:
// ❌ unsafe
import jsPDF from 'jspdf';
const doc = new jsPDF();
const html = new URLSearchParams(location.search).get('content');
doc.html(html);

good_examples:
// ✅ safe
import jsPDF from 'jspdf';
import DOMPurify from 'dompurify';
const doc = new jsPDF();
const html = new URLSearchParams(location.search).get('content') ?? '';
doc.html(DOMPurify.sanitize(html));

bad_examples:
// ❌ unsafe
import html2pdf from 'html2pdf.js';
const userHtml = new URLSearchParams(location.search).get('html');
html2pdf(userHtml);

good_examples:
// ✅ safe - pass a DOM element
import html2pdf from 'html2pdf.js';
import DOMPurify from 'dompurify';
const container = document.createElement('div');
container.innerHTML = DOMPurify.sanitize(userHtml);
html2pdf(container);

bad_examples:
// ❌ unsafe - no signature verification
import jwt from 'jsonwebtoken';
const payload = jwt.decode(token); // forged tokens trusted
if ((payload as any).role === 'admin') grantAccess();

good_examples:
// ✅ safe - verify with explicit algorithm
import jwt from 'jsonwebtoken';
try {
  const payload = jwt.verify(token, process.env.JWT_SECRET!, {
    algorithms: ['HS256']
  });
  if ((payload as any).role === 'admin') grantAccess();
} catch {
  denyAccess();
}

bad_examples:
// ❌ unsafe
const label = new URLSearchParams(location.search).get('label');
d3.select('#tooltip').html(label);
d3.select('a').attr('href', `javascript:${userInput}`);

good_examples:
// ✅ safe - .text() for user content
const label = new URLSearchParams(location.search).get('label') ?? '';
d3.select('#tooltip').text(label); // textContent, no HTML parsing

bad_examples:
// ❌ unsafe
const title = new URLSearchParams(location.search).get('title');
Highcharts.chart('container', {
  title: { text: title, useHTML: true }
});

good_examples:
// ✅ safe - sanitize or disable useHTML
import DOMPurify from 'dompurify';
const rawTitle = new URLSearchParams(location.search).get('title') ?? '';
Highcharts.chart('container', {
  title: { text: DOMPurify.sanitize(rawTitle), useHTML: true }
});
